// Load event from trigger
const event = $json.event || $json.body || $json;

// Ensure required fields
return {
  ...event,
  timestamp: new Date().toISOString()
};

// Determine identity confidence based on contact resolution
const event = $json;
const contact = Array.isArray($json) && $json.length > 0 ? $json[0] : null;
const email = event.email;
const phoneE164 = event.phone_e164;

let confidence = 'none';
let contactId = null;

if (contact) {
  contactId = contact.id;
  const emailMatch = email && contact.email && email.toLowerCase() === contact.email.toLowerCase();
  const phoneMatch = phoneE164 && contact.phone_normalized && phoneE164 === contact.phone_normalized;

  if (emailMatch && phoneMatch) {
    confidence = 'high';
  } else if (emailMatch || phoneMatch) {
    confidence = 'medium';
  } else {
    confidence = 'low';
  }
} else {
  confidence = 'none';
}

return {
  ...event,
  identity_confidence: confidence,
  contact_id: contactId,
  matched_contact: contact
};

// Medium confidence: ask soft verification question before loading context
const event = $json;
const contactName = event.matched_contact?.name || 'dear friend';

return {
  ...event,
  verification_question: `Just to confirm — are you ${contactName}? I want to make sure I pull up your right information.`,
  context_access_allowed: false
};

// High or low confidence: load context based on policy
const event = $json;
const confidence = event.identity_confidence;

let contextAccessAllowed = false;
if (confidence === 'high') {
  contextAccessAllowed = true; // High confidence: load all context
} else if (confidence === 'low' || confidence === 'none') {
  contextAccessAllowed = false; // Low/none: do not load private context
}

return {
  ...event,
  context_access_allowed: contextAccessAllowed
};

